package com.hospital.management.controller.billing;import com.hospital.management.service.*;import com.hospital.management.service.impl.PaymentServiceImpl;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.*;@WebServlet("/billing/payment/refund")public class PaymentRefundServlet extends HttpServlet{private final PaymentService service;public PaymentRefundServlet(){this(new PaymentServiceImpl());}public PaymentRefundServlet(PaymentService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws IOException{r.sendError(405);}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws IOException{Long p=BillingRequest.id(q.getParameter("paymentId")),b=BillingRequest.id(q.getParameter("billId"));if(p==null||b==null){r.sendError(400);return;}ServiceResult<Void>x=service.refundPayment(p,BillingRequest.audit(q),BillingRequest.user(q));r.sendRedirect(q.getContextPath()+"/billing/view?id="+b+"&"+(x.isSuccess()?"message=refunded":"error=refund"));}}
